def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-9
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 3:
            priority = (ratio ** 5) + np.sin(capacity) * 10
            for k in range(1, int(capacity * 1.5) + 3):
                if k % 4 == 0:
                    priority += np.exp(-k / (ratio + epsilon))
                elif k % 3 == 0:
                    priority -= (np.log(k + ratio + epsilon) ** 2) / (k + epsilon)
                else:
                    priority += np.sqrt(k) * (ratio / (k + epsilon))
            if capacity % 2 == 0:
                priority *= 1.15
            else:
                priority /= 1.07
            if priority > 1000:
                priority = np.log(priority + epsilon) * 500
        elif 2 < ratio <= 3:
            priority = (ratio ** 3) * np.sqrt(capacity + 1)
            sum_factor = 0
            for m in range(1, int(item * 2) + 1):
                if m % 5 == 0:
                    sum_factor += np.cos(m) * (m / (capacity + 1))
                else:
                    sum_factor -= (m ** 2) / ((item + epsilon) * (capacity + 1))
            priority += sum_factor
            if priority < 0:
                priority = abs(priority) / 2
        elif 1 < ratio <= 2:
            priority = (ratio ** 2) * np.log(capacity + 1)
            for m in range(1, int(item) + 1):
                if m % 3 == 0:
                    priority += (m / (capacity + 1)) ** 2
                else:
                    priority -= m / (item + epsilon)
            priority = max(priority, 0)
            weight = 1
            for n in range(1, 4):
                weight *= (ratio + np.tanh(n / (capacity + 1)))
            priority *= weight
        elif 0.5 < ratio <= 1:
            priority = -np.log(1 - ratio + epsilon) * np.exp(-capacity / (item + epsilon))
            factor = 1
            for n in range(1, 6):
                factor *= (ratio + n / (capacity + 2))
                if factor > 10:
                    factor /= 2
            priority *= factor
            if int(capacity) % 2 == 1:
                priority += np.sqrt(capacity)
        elif 0.2 < ratio <= 0.5:
            total = 0
            for j in range(1, int(capacity) + 1):
                val = (ratio ** j) / (j + epsilon)
                if j % 2 == 0:
                    val *= -1
                total += val
            priority = abs(total) + 0.5
            penalty_factor = 1
            for p in range(1, int(item) + 1):
                if p % 2 == 0:
                    penalty_factor += np.log(p + 1)
                else:
                    penalty_factor -= p * 0.05
            priority *= max(penalty_factor, 0.1)
        else:
            priority = 0
            for x in range(1, int(capacity) + 2):
                temp = ((item + x) % (capacity + 1)) * np.sin(ratio * x)
                if x % 2 == 0:
                    priority += np.abs(temp)
                else:
                    priority -= np.abs(temp)
            priority = abs(priority) + 1
            if capacity < item * 0.5:
                penalty = (item - capacity) * 20
                for q in range(1, int(item - capacity) + 1):
                    if q % 3 == 0:
                        penalty += np.cos(q)
                    else:
                        penalty -= q * 0.2
                penalty = max(penalty, 0)
                priority += penalty
        if capacity < item:
            diff = (item - capacity)
            penalty = diff * 10
            for p in range(1, int(diff) + 1):
                if p % 2 == 0:
                    penalty += np.log(p + 2)
                else:
                    penalty -= p * 0.15
            penalty = max(penalty, 0)
            priority += penalty
        priorities[i] = priority
    return priorities
